// ─── Helper functions ──────────────────────────────────────────────────────

function bioFromOccupation(name, occupation, partyCode) {
  const firstName = name.split(' ')[0];
  const occLower = occupation.toLowerCase();
  const bios = {
    D: `${firstName} er ${occLower} og hefur brennandi áhuga á að efla frjálst atvinnulíf og skynsamlega fjármálastjórnun í þágu sveitarfélagsins.`,
    B: `${firstName} er ${occLower} sem leggur ríka áherslu á sjálfbæra þróun og öfluga þjónustu við alla íbúa.`,
    S: `${firstName} er ${occLower} sem hefur helgað sig baráttu fyrir jafnrétti og betri velferðarþjónustu.`,
    V: `Umhverfismál og félagslegt réttlæti hafa alltaf verið hjartans mál ${firstName}. Sem ${occLower} vinnur hann/hún að sjálfbærari framtíð.`,
    A: `${firstName} er ${occLower} og trúir á að saman erum við sterkari. Hún/hann vinnur að réttlátara og grænna samfélagi.`,
    P: `${firstName} er ${occLower} og stafrænn málsvari sem trúir á opið lýðræði og gagnsæja stjórnsýslu.`,
    M: `${firstName} er ${occLower} og trúir á að grunnþjónustan eigi alltaf að vera í forgangi, áður en stórfjárfestingar eru hafnar.`,
    F: `${firstName} er ${occLower} sem þreytist á hefðbundinni pólitík og vill heiðarlegar og beinar lausnir í þágu íbúanna.`,
    C: `${firstName} er ${occLower} sem trúir á nýsköpun, hagkvæmni og framsynta stjórnun í þágu allra íbúa.`,
    J: `${firstName} er ${occLower} og trúir á samstöðu, réttlæti og að samfélagið geti séð um alla sína meðlimi.`,
  };
  return bios[partyCode] || `${firstName} er ${occLower} með brennandi áhuga á að þjóna sveitarfélaginu.`;
}

function deterministicAge(name, index) {
  const code = name.split('').reduce((a, c) => a + c.charCodeAt(0), 0);
  return 27 + ((code * 7 + index * 13) % 38);
}

function deterministicInterests(name) {
  const all = ['Íþróttir', 'Menning', 'Tónlist', 'Lestur', 'Útivist', 'Samfélagsstarfsemi', 'Tækni', 'Matreiðsla', 'Ferðalög', 'Listir', 'Náttúra', 'Sjávarútvegur'];
  const code = name.split('').reduce((a, c) => a + c.charCodeAt(0), 0);
  const i1 = code % all.length;
  const i2 = (code * 3) % all.length;
  const i3 = (code * 7) % all.length;
  const items = [all[i1]];
  if (i2 !== i1) items.push(all[i2]);
  if (i3 !== i1 && i3 !== i2 && items.length < 3) items.push(all[i3]);
  return items;
}

// ─── Local avatar generator (no external dependency) ─────────────────────────
function localAvatar(name) {
  const initials = name.trim().split(/\s+/).slice(0, 2).map(w => w[0] || '').join('').toUpperCase();
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="300" height="300" viewBox="0 0 300 300"><rect width="300" height="300" fill="#1c2335"/><text x="150" y="155" text-anchor="middle" dominant-baseline="middle" fill="#8892a4" font-family="Arial,sans-serif" font-size="120" font-weight="bold">${initials}</text></svg>`;
  return `data:image/svg+xml,${encodeURIComponent(svg)}`;
}

function makeCandidatesFromList(municipalityId, partyCode, list) {
  return list.map(([ballotOrder, name, occupation, photoUrl, realData]) => ({
    id: `${municipalityId}-${partyCode}-${ballotOrder}`,
    ballotOrder,
    name,
    occupation,
    // Photo paths in the data are relative ("images/candidates/<hash>.jpg").
    // On legacy URLs at /municipality.html that resolves to /images/... fine,
    // but on Phase 2 path-based URLs like /<muni>/<party>/ a relative path
    // resolves to /<muni>/<party>/images/... which 404s. Force root-absolute
    // for any non-absolute, non-data path.
    imageUrl: (photoUrl && /^(https?:|data:|\/)/.test(photoUrl))
      ? photoUrl
      : (photoUrl ? '/' + photoUrl : localAvatar(name)),
    age:       realData?.age       ?? null,
    bio:       realData?.bio       ?? null,
    heimild:   realData?.heimild   ?? null,
    interests: realData?.interests ?? null,
    social:    realData?.social    ?? null,
    news:      realData?.news      ?? null,
  }));
}

