// ─── Seeded RNG fallback (for municipalities not yet populated with real data) ─

function seededRandom(seed) {
  let s = seed;
  return function() {
    s = (s * 1664525 + 1013904223) & 0xffffffff;
    return (s >>> 0) / 0xffffffff;
  };
}

const ICELANDIC_NAMES_F = ['Sigríður', 'Kristín', 'Helga', 'Þóra', 'Guðrún', 'Anna', 'Ragnheiður', 'Lilja', 'Birta', 'Hanna', 'Elín', 'Jóhanna', 'María', 'Sigrún', 'Þórunn', 'Katrín', 'Áslaug', 'Bergþóra', 'Valdís', 'Þórunn'];
const ICELANDIC_NAMES_M = ['Jón', 'Gunnar', 'Björn', 'Sigurður', 'Óskar', 'Magnús', 'Árni', 'Páll', 'Þorsteinn', 'Davíð', 'Eiríkur', 'Ragnar', 'Stefán', 'Kristján', 'Bjarni', 'Ingvar', 'Haraldur', 'Friðrik', 'Valdimar', 'Helgi'];
const SURNAMES_F = ['Sigurðardóttir', 'Jónsdóttir', 'Magnúsdóttir', 'Björnsdóttir', 'Guðmundsdóttir', 'Arnadóttir', 'Einardóttir', 'Bjarnardóttir', 'Ólafsdóttir', 'Kristjánsdóttir', 'Stefánsdóttir', 'Pálsdóttir'];
const SURNAMES_M = ['Sigurðsson', 'Jónsson', 'Magnússon', 'Björnsson', 'Guðmundsson', 'Arnarsson', 'Einarsson', 'Bjarnason', 'Ólafsson', 'Kristjánsson', 'Stefánsson', 'Pálsson'];
const OCCUPATIONS = ['Lögfræðingur', 'Kennari', 'Læknir', 'Verkfræðingur', 'Frumkvöðull', 'Félagsráðgjafi', 'Arkitekt', 'Hagfræðingur', 'Hjúkrunarfræðingur', 'Listamaður', 'Blaðamaður', 'Viðskiptafræðingur', 'Sálfræðingur', 'Tölvunarfræðingur', 'Umhverfisfræðingur', 'Félagsfræðingur', 'Rekstrarstjóri', 'Sjómaður', 'Bóndi', 'Iðnaðarmaður'];

function generateCandidates(municipalityId, partyCode, count = 8) {
  const seed = municipalityId.split('').reduce((a, c) => a + c.charCodeAt(0), 0) * 31 +
               partyCode.charCodeAt(0) * 17;
  const rng = seededRandom(seed);
  return Array.from({ length: count }, (_, i) => {
    const female = rng() > 0.5;
    const first = (female ? ICELANDIC_NAMES_F : ICELANDIC_NAMES_M)[Math.floor(rng() * 20)];
    const last = (female ? SURNAMES_F : SURNAMES_M)[Math.floor(rng() * 12)];
    const name = `${first} ${last}`;
    const occupation = OCCUPATIONS[Math.floor(rng() * OCCUPATIONS.length)];
    const age = 27 + Math.floor(rng() * 40);
    return {
      id: `${municipalityId}-${partyCode}-${i + 1}`,
      ballotOrder: i + 1,
      name,
      occupation,
      imageUrl: localAvatar(name),
      age,
      bio: bioFromOccupation(name, occupation, partyCode),
      interests: deterministicInterests(name),
    };
  });
}

