// ─── Public API ────────────────────────────────────────────────────────────────

const REAL_DATA = { reykjavik: RVK, kopavogur: KOP, hafnarfjordur: HAF, gardabaer: GAR, mosfellsbaer: MOS, akureyri: AKU, seltjarnarnes: SEL, reykjanesbaer: RNB, vogar: VOG, grindavik: GRN, sudurnesjabaer: SNB, arborg: ARB, vestmannaeyjar: VME, nordurping: NPG, fjallabyggd: FJB, fjardabyggd: FJD, hornafjordur: HFJ, akranes: AKR, borgarbyggd: BBD, isafjordur: ISF, hveragerdi: HVG, rangarthingeystra: RTE, rangarthingytra: RTY, olfus: OLF, skaftarhreppur: SKR, myrdalshr: MYR, blaskogabyggd: BSG, floahreppur: FHR, hrunamannahreppur: HMR, grimsnesgrafningur: GGR, skeidagnup: SGN, dalvikurbyggd: DVB, eyjafjardarsveit: EJA, horgarsv: HGS, hunabyggd: HNB, hunathing: HNT, skagafjordur: SFJ, skagastrond: SST, stykkisholmur: STK, grundarfjordur: GFJ, bolungarvik: BLV, sudavik: SDV, vesturbyggd: VBG, strandabyggd: STD, reykholar: RKH, mulathing: MUT, thingeyjarsveit: THV, hvalfjardarsveit: HVF, snaefellsbaer: SNF, svalbardsstrond: SVS, kjosarhreppur: KJO, vopnafjordur: VPF, tjornes: TJR, arneshr: ARN };

export function getMunicipalityPartyData(municipalityId, partyCode) {
  const muniReal = REAL_DATA[municipalityId];
  if (muniReal && muniReal[partyCode]) {
    const real = muniReal[partyCode];
    return {
      municipalityId,
      partyCode,
      // Optional per-muni override for the party display name. Lets a local
      // list use a different label than the global PARTIES[code].name —
      // e.g. X-B in Strandabyggð is called "Framsókn og óháðir" rather
      // than "Framsóknarflokkurinn".
      partyName: real.partyName || null,
      partyShortName: real.partyShortName || real.partyName || null,
      tagline: real.tagline,
      agenda: real.agenda,
      platformUrl: real.platformUrl || null,
      // Placeholder = no real agenda. A real party can have a verified agenda
      // without a public platform URL (e.g. provided directly by the party);
      // in that case we still render the agenda but skip the 'Heimild' link.
      isPlaceholder: !real.agenda || real.agenda.length === 0,
      candidates: makeCandidatesFromList(municipalityId, partyCode, real.list),
    };
  }

  const agenda = DEFAULT_AGENDAS[partyCode] || DEFAULT_AGENDAS.D;
  const count = ['reykjavik', 'kopavogur', 'akureyri', 'hafnarfjordur'].includes(municipalityId) ? 12 : 8;
  return {
    municipalityId,
    partyCode,
    tagline: agenda.tagline,
    agenda: agenda.agenda,
    platformUrl: null,
    isPlaceholder: true,
    candidates: generateCandidates(municipalityId, partyCode, count),
  };
}
